# scripts/drift_scan.py — run on schedule or post-deploy
import json, subprocess, pathlib, datetime, sys

BASELINE = pathlib.Path("architecture/baseline.json")
THRESHOLDS = {
    "coupling_score": {"warn": 0.7, "crit": 0.85},
    "boundary_violations": {"warn": 3, "crit": 5},
    "max_complexity": {"warn": 12, "crit": 20},
}

def collect_metrics() -> dict:
    # Run analysis tools and collect current metrics
    result = subprocess.run(
        ["python", "scripts/analyze_architecture.py", "--json"],
        capture_output=True, text=True, check=True
    )
    return json.loads(result.stdout)

def classify_drift(metric: str, current: float, baseline: float) -> str:
    delta = abs(current - baseline)
    threshold = THRESHOLDS.get(metric, {})
    if current >= threshold.get("crit", float("inf")):
        return "CRIT"
    elif current >= threshold.get("warn", float("inf")):
        return "WARN"
    return "INFO"

def main():
    current = collect_metrics()
    baseline = json.loads(BASELINE.read_text())

    drifts = []
    for metric, value in current.items():
        if metric in baseline:
            severity = classify_drift(metric, value, baseline[metric])
            if severity != "INFO" or value != baseline[metric]:
                drifts.append({
                    "metric": metric,
                    "baseline": baseline[metric],
                    "current": value,
                    "severity": severity
                })

    report = {
        "scan_time": datetime.datetime.utcnow().isoformat(),
        "drifts": drifts
    }
    print(json.dumps(report, indent=2))

    # Exit non-zero on critical drift
    if any(d["severity"] == "CRIT" for d in drifts):
        sys.exit(1)

if __name__ == "__main__":
    main()
